const token = $json.access_token;
const conId = $('Config').first().json['GROUP_CON_MFA_ID'];
const sinId = $('Config').first().json['GROUP_SIN_MFA_ID'];
let script = `
const https = require('https');
const fs = require('fs');

const TOKEN = '__TOKEN__';
const GROUP_CON_ID = '__GROUP_CON_ID__';
const GROUP_SIN_ID = '__GROUP_SIN_ID__';
const OUTPUT = '/tmp/azure_mfa_report.json';

function graphGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, { headers: { 'Authorization': 'Bearer ' + TOKEN } }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        try { resolve(JSON.parse(d)); }
        catch(e) { reject(new Error('Parse error')); }
      });
    }).on('error', reject);
  });
}

async function paginate(url) {
  const results = [];
  while (url) {
    const d = await graphGet(url);
    if (d.error) { console.error('API Error:', d.error.message); break; }
    results.push(...(d.value || []));
    url = d['@odata.nextLink'] || null;
    if (results.length % 500 === 0) console.log('  ...' + results.length);
  }
  return results;
}

async function paginateIds(url) {
  const ids = new Set();
  while (url) {
    const d = await graphGet(url);
    if (d.error) { console.error('API Error:', d.error.message); break; }
    (d.value || []).forEach(m => ids.add(m.id));
    url = d['@odata.nextLink'] || null;
  }
  return ids;
}

async function main() {
  console.log('Fetching enabled users (beta, with signInActivity)...');
  const users = await paginate(
    'https://graph.microsoft.com/beta/users?$filter=accountEnabled%20eq%20true' +
    '&$select=id,displayName,mail,userPrincipalName,userType,createdDateTime,department,jobTitle,companyName,signInActivity' +
    '&$top=100'
  );
  console.log('Total enabled users: ' + users.length);

  console.log('Fetching AZ_USERS_CON_MFA...');
  const conIds = await paginateIds(
    'https://graph.microsoft.com/v1.0/groups/' + GROUP_CON_ID + '/members?$select=id&$top=100'
  );
  console.log('  CON_MFA: ' + conIds.size);

  console.log('Fetching AZ_USERS_SIN_MFA...');
  const sinIds = await paginateIds(
    'https://graph.microsoft.com/v1.0/groups/' + GROUP_SIN_ID + '/members?$select=id&$top=100'
  );
  console.log('  SIN_MFA: ' + sinIds.size);

  const excluded = new Set([...conIds, ...sinIds]);
  const filtered = users.filter(u => u.userType !== 'Guest' && !excluded.has(u.id));
  console.log('Result: ' + filtered.length + ' users without MFA group');

  const now = new Date();
  const rows = filtered.map(u => {
    const sia = u.signInActivity || {};
    const lastI = sia.lastSignInDateTime || null;
    const lastNI = sia.lastNonInteractiveSignInDateTime || null;
    let latest = null;
    if (lastI && lastNI) latest = new Date(lastI) > new Date(lastNI) ? lastI : lastNI;
    else latest = lastI || lastNI;
    let days = null;
    if (latest) days = Math.floor((now - new Date(latest)) / 86400000);
    return {
      displayName: u.displayName || '',
      mail: u.mail || '',
      upn: u.userPrincipalName || '',
      department: u.department || '',
      jobTitle: u.jobTitle || '',
      company: u.companyName || '',
      created: (u.createdDateTime || '').substring(0, 10),
      lastLogin: lastI || 'Nunca',
      lastNonInteractive: lastNI || 'Nunca',
      days: days !== null ? days : 'N/A'
    };
  });
  rows.sort((a, b) => {
    const da = a.days === 'N/A' ? 999999 : a.days;
    const db = b.days === 'N/A' ? 999999 : b.days;
    return db - da;
  });

  fs.writeFileSync(OUTPUT, JSON.stringify(rows));
  const noLogin = rows.filter(r => r.lastLogin === 'Nunca').length;
  const old90 = rows.filter(r => typeof r.days === 'number' && r.days > 90).length;
  console.log('Stats: ' + noLogin + ' never logged in, ' + old90 + ' >90 days');
  console.log('DONE: ' + rows.length + ' rows saved');
}
main().catch(e => { console.error('FATAL:', e); process.exit(1); });
`;
script = script.replace('__TOKEN__', token);
script = script.replace('__GROUP_CON_ID__', conId);
script = script.replace('__GROUP_SIN_ID__', sinId);
const b64 = Buffer.from(script).toString('base64');
return [{ json: { scriptB64: b64 } }];

let script = `
const fs = require('fs');
const zlib = require('zlib');

const rows = JSON.parse(fs.readFileSync('/tmp/azure_mfa_report.json', 'utf8'));
console.log('Building Excel for ' + rows.length + ' users...');

function esc(s) {
  if (s == null) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

const hdrs = ['Nombre','Email','UPN','Departamento','Puesto','Empresa',
  'Fecha creación','Último login interactivo','Último login no interactivo','Días sin login'];

const ssMap = new Map();
const ssList = [];
function addSS(s) { const k = String(s); if (!ssMap.has(k)) { ssMap.set(k, ssList.length); ssList.push(k); } return ssMap.get(k); }
hdrs.forEach(addSS);
rows.forEach(r => {
  [r.displayName, r.mail, r.upn, r.department, r.jobTitle, r.company,
   r.created, r.lastLogin, r.lastNonInteractive, String(r.days)].forEach(addSS);
});

function col(c) { let s=''; while(c>=0){s=String.fromCharCode(65+(c%26))+s;c=Math.floor(c/26)-1;} return s; }

let sd = '';
sd += '<row r="1">';
hdrs.forEach((h,i) => { sd += '<c r="'+col(i)+'1" t="s" s="1"><v>'+addSS(h)+'</v></c>'; });
sd += '</row>\\n';
rows.forEach((r,ri) => {
  const rn = ri+2;
  const vals = [r.displayName,r.mail,r.upn,r.department,r.jobTitle,r.company,
    r.created,r.lastLogin,r.lastNonInteractive,String(r.days)];
  sd += '<row r="'+rn+'">';
  vals.forEach((v,ci) => {
    let st = '0';
    if (ci===9 && v!=='N/A' && parseInt(v)>90) st='2';
    if (ci===9 && v==='N/A') st='2';
    sd += '<c r="'+col(ci)+rn+'" t="s" s="'+st+'"><v>'+addSS(v)+'</v></c>';
  });
  sd += '</row>\\n';
});

const sheet = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">\\n'+
  '<cols><col min="1" max="1" width="35" customWidth="1"/><col min="2" max="2" width="35" customWidth="1"/>'+
  '<col min="3" max="3" width="40" customWidth="1"/><col min="4" max="4" width="20" customWidth="1"/>'+
  '<col min="5" max="5" width="25" customWidth="1"/><col min="6" max="6" width="15" customWidth="1"/>'+
  '<col min="7" max="7" width="14" customWidth="1"/><col min="8" max="8" width="24" customWidth="1"/>'+
  '<col min="9" max="9" width="24" customWidth="1"/><col min="10" max="10" width="14" customWidth="1"/></cols>\\n'+
  '<sheetData>\\n'+sd+'</sheetData>\\n'+
  '<autoFilter ref="A1:J'+(rows.length+1)+'"/>\\n</worksheet>';

const ss = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="'+
  (hdrs.length + rows.length*10)+'" uniqueCount="'+ssList.length+'">\\n'+
  ssList.map(s=>'<si><t>'+esc(s)+'</t></si>').join('\\n')+'\\n</sst>';

const styles = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">\\n'+
  '<fonts count="2"><font><sz val="11"/><name val="Calibri"/></font>'+
  '<font><b/><sz val="11"/><color rgb="FFFFFFFF"/><name val="Calibri"/></font></fonts>\\n'+
  '<fills count="4"><fill><patternFill patternType="none"/></fill>'+
  '<fill><patternFill patternType="gray125"/></fill>'+
  '<fill><patternFill patternType="solid"><fgColor rgb="FF2F5496"/></patternFill></fill>'+
  '<fill><patternFill patternType="solid"><fgColor rgb="FFFFC7CE"/></patternFill></fill></fills>\\n'+
  '<borders count="1"><border><left/><right/><top/><bottom/><diagonal/></border></borders>\\n'+
  '<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>\\n'+
  '<cellXfs count="3">'+
  '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"/>'+
  '<xf numFmtId="0" fontId="1" fillId="2" borderId="0" xfId="0" applyFont="1" applyFill="1" applyAlignment="1"><alignment horizontal="center" wrapText="1"/></xf>'+
  '<xf numFmtId="0" fontId="0" fillId="3" borderId="0" xfId="0" applyFill="1"><alignment horizontal="center"/></xf>'+
  '</cellXfs>\\n</styleSheet>';

const ct = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'+
  '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'+
  '<Default Extension="xml" ContentType="application/xml"/>'+
  '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'+
  '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>'+
  '<Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>'+
  '<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>'+
  '</Types>';

const rels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+
  '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/></Relationships>';

const wbr = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+
  '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>'+
  '<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" Target="sharedStrings.xml"/>'+
  '<Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>';

const wb = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\\n'+
  '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'+
  '<sheets><sheet name="Usuarios sin grupo MFA" sheetId="1" r:id="rId1"/></sheets></workbook>';

// ===== Pure Node.js ZIP builder using zlib.deflateRawSync =====
const files = [
  { name: '[Content_Types].xml', data: Buffer.from(ct, 'utf8') },
  { name: '_rels/.rels', data: Buffer.from(rels, 'utf8') },
  { name: 'xl/workbook.xml', data: Buffer.from(wb, 'utf8') },
  { name: 'xl/_rels/workbook.xml.rels', data: Buffer.from(wbr, 'utf8') },
  { name: 'xl/worksheets/sheet1.xml', data: Buffer.from(sheet, 'utf8') },
  { name: 'xl/sharedStrings.xml', data: Buffer.from(ss, 'utf8') },
  { name: 'xl/styles.xml', data: Buffer.from(styles, 'utf8') },
];

function crc32(buf) {
  let table = crc32.table;
  if (!table) {
    table = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c;
    }
    crc32.table = table;
  }
  let crc = 0xFFFFFFFF;
  for (let i = 0; i < buf.length; i++) crc = table[(crc ^ buf[i]) & 0xFF] ^ (crc >>> 8);
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

function buildZip(entries) {
  const localHeaders = [];
  const centralHeaders = [];
  let offset = 0;

  for (const entry of entries) {
    const nameB = Buffer.from(entry.name, 'utf8');
    const raw = entry.data;
    const compressed = zlib.deflateRawSync(raw);
    const crc = crc32(raw);

    // Local file header (30 + nameLen + compressedLen)
    const lh = Buffer.alloc(30 + nameB.length);
    lh.writeUInt32LE(0x04034b50, 0);   // signature
    lh.writeUInt16LE(20, 4);            // version needed
    lh.writeUInt16LE(0, 6);             // flags
    lh.writeUInt16LE(8, 8);             // compression: deflate
    lh.writeUInt16LE(0, 10);            // mod time
    lh.writeUInt16LE(0, 12);            // mod date
    lh.writeUInt32LE(crc, 14);          // crc32
    lh.writeUInt32LE(compressed.length, 18); // compressed size
    lh.writeUInt32LE(raw.length, 22);   // uncompressed size
    lh.writeUInt16LE(nameB.length, 26); // filename length
    lh.writeUInt16LE(0, 28);            // extra field length
    nameB.copy(lh, 30);

    localHeaders.push(Buffer.concat([lh, compressed]));

    // Central directory header
    const ch = Buffer.alloc(46 + nameB.length);
    ch.writeUInt32LE(0x02014b50, 0);    // signature
    ch.writeUInt16LE(20, 4);            // version made by
    ch.writeUInt16LE(20, 6);            // version needed
    ch.writeUInt16LE(0, 8);             // flags
    ch.writeUInt16LE(8, 10);            // compression: deflate
    ch.writeUInt16LE(0, 12);            // mod time
    ch.writeUInt16LE(0, 14);            // mod date
    ch.writeUInt32LE(crc, 16);          // crc32
    ch.writeUInt32LE(compressed.length, 20); // compressed size
    ch.writeUInt32LE(raw.length, 24);   // uncompressed size
    ch.writeUInt16LE(nameB.length, 28); // filename length
    ch.writeUInt16LE(0, 30);            // extra field length
    ch.writeUInt16LE(0, 32);            // comment length
    ch.writeUInt16LE(0, 34);            // disk number start
    ch.writeUInt16LE(0, 36);            // internal attrs
    ch.writeUInt32LE(0, 38);            // external attrs
    ch.writeUInt32LE(offset, 42);       // local header offset
    nameB.copy(ch, 46);

    centralHeaders.push(ch);
    offset += lh.length + compressed.length;
  }

  const centralDir = Buffer.concat(centralHeaders);
  const centralDirOffset = offset;

  // End of central directory
  const eocd = Buffer.alloc(22);
  eocd.writeUInt32LE(0x06054b50, 0);
  eocd.writeUInt16LE(0, 4);
  eocd.writeUInt16LE(0, 6);
  eocd.writeUInt16LE(entries.length, 8);
  eocd.writeUInt16LE(entries.length, 10);
  eocd.writeUInt32LE(centralDir.length, 12);
  eocd.writeUInt32LE(centralDirOffset, 16);
  eocd.writeUInt16LE(0, 20);

  return Buffer.concat([...localHeaders, centralDir, eocd]);
}

const zipBuf = buildZip(files);
const out = '/tmp/usuarios_sin_mfa.xlsx';
fs.writeFileSync(out, zipBuf);
const b64 = zipBuf.toString('base64');
fs.writeFileSync('/tmp/xlsx_b64.txt', b64);
console.log('Excel: ' + zipBuf.length + ' bytes, b64: ' + b64.length);
console.log('DONE');
`;
const b64 = Buffer.from(script).toString('base64');
return [{ json: { scriptB64: b64 } }];

const xlsxB64 = $json.stdout.trim();
const emailTo = $('Config').first().json['EMAIL_TO'];
const emailFrom = $('Config').first().json['EMAIL_FROM'];
const now = new Date().toISOString().substring(0, 10);
const po = $('Fetch & Filter Users').first().json.stdout || '';
const rc = (po.match(/Result: (\d+) users/) || [])[1] || '?';
const nc = (po.match(/(\d+) never logged/) || [])[1] || '?';
const oc = (po.match(/(\d+) >90 days/) || [])[1] || '?';
const subject = 'Usuarios sin grupo MFA - Reporte ' + now;
const html = '<html><body style="font-family:Arial,sans-serif;font-size:14px;color:#333">'
  + '<h2 style="color:#2F5496">Reporte de usuarios sin grupo MFA</h2>'
  + '<p>Se adjunta el listado de usuarios habilitados en Azure AD que <b>no pertenecen</b> a:</p>'
  + '<ul><li><b>AZ_USERS_CON_MFA</b></li><li><b>AZ_USERS_SIN_MFA</b></li></ul>'
  + '<table style="border-collapse:collapse;margin:16px 0">'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Total usuarios:</td><td>' + rc + '</td></tr>'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Sin login nunca:</td><td>' + nc + '</td></tr>'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Último login &gt; 90 días:</td><td>' + oc + '</td></tr>'
  + '</table>'
  + '<p>Fecha: <b>' + now + '</b></p>'
  + '<p style="font-size:12px;color:#999;margin-top:24px">Generado automáticamente por n8n.</p>'
  + '</body></html>';
const fileName = 'Usuarios_Sin_Grupo_MFA_' + now + '.xlsx';
return [{
  json: { subject, html, emailTo, emailFrom, fileName },
  binary: {
    attachment: {
      data: xlsxB64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: fileName
    }
  }
}];
